import { Component } from "react";
import Logo from './Logo'

const redesSociales = [
    {nombre: 'Github', enlace: 'https://github.com/TheJhoxX', img: '/githubLogo.svg'},
    {nombre: 'Linkedin', enlace: 'www.linkedin.com/in/victor-jorge-sibaja-156899196', img: '/linkedinLogo.svg'}
]

class Seccion extends Component {
    render() {
        const { nombre } = this.props
        return( 
            <div id={nombre} className="seccion-portfolio">
                <h1>{ nombre }</h1>
                <Logo redesSociales={redesSociales}/>
            </div>
        )
    }
}

export default Seccion
